commands.cmd:
@(25,80,443,587,3389,445) | ForEach-Object {
    $r = Test-NetConnection -ComputerName '{host}' -Port $_ -WarningAction SilentlyContinue
    [PSCustomObject]@{ Port=$_; Erreichbar=$r.TcpTestSucceeded; Latenz="$([math]::Round($r.PingReplyDetails.RoundtripTime,0))ms" }
} | Format-Table -AutoSize

@('outlook.office365.com','smtp.office365.com','login.microsoftonline.com','graph.microsoft.com') | ForEach-Object {
    $r = Test-NetConnection -ComputerName $_ -Port 443 -WarningAction SilentlyContinue
    [PSCustomObject]@{ Host=$_; Port=443; OK=$r.TcpTestSucceeded }
} | Format-Table -AutoSize
